import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid } from '@mui/material';
import { BarChart, PieChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklySpending {
  day: string;
  amount: number;
}

interface CategoryBreakdown {
  category: string;
  value: number;
}

interface ExpenseData {
  totalSpent: number;
  weeklySpending: WeeklySpending[];
  categoryBreakdown: CategoryBreakdown[];
}

export default function Widget() {
  const expenseData = response.data as ExpenseData;
  const { totalSpent, weeklySpending, categoryBreakdown } = expenseData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#303030', color: '#E0E0E0' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={3}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Total Spent This Week
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFC107' }}>
              ${totalSpent.toFixed(2)}
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: weeklySpending.map(d => d.amount),
                color: '#4CAF50',
              },
            ]}
            xAxis={[
              {
                data: weeklySpending.map(d => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#B0BEC5',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />

          <Box sx={{ width: '100%', height: 220 }}>
            <PieChart
              height={220}
              series={[
                {
                  data: categoryBreakdown.map(c => ({ value: c.value, label: c.category })),
                  color: ['#4CAF50', '#FFC107', '#FF5722', '#03A9F4', '#9E9E9E'],
                },
              ]}
              labelStyle={{ fontSize: 10, fill: '#E0E0E0' }}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            />
          </Box>

          <Grid container spacing={1}>
            {categoryBreakdown.map((category, index) => (
              <Grid item xs={6} key={index}>
                <Typography variant="body2" sx={{ fontSize: '10px', color: '#B0BEC5' }}>
                  {category.category}: ${category.value.toFixed(2)}
                </Typography>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
